/*
 * Acest schelet citește datele de intrare și scrie răspunsul generat de voi,
 * astfel că e suficient să completați cele două funcții.
 *
 * Scheletul este doar un punct de plecare, îl puteți modifica oricum doriți:
 * puteți schimba parametrii, reordona funcțiile etc.
 */

#include <cstdint>
#include <fstream>
#include <vector>
#include <algorithm>
#include <iostream>
#include <iterator>

using namespace std;


int64_t SolveTask1(vector<int>& a, vector<int>& b, int n) {
    std::sort(a.begin(), a.end(), std::greater<int>());
    std::sort(b.begin(), b.end());

    long sum = 0;
    int i = 0;
    // get all the highest n numbers in the b array
    while (b[i] < a[i]) {
        int aux = a[i];
        a[i] = b[i];
        b[i] = aux;
        i++;
    }

    for (int i = 0; i < n; i++) {
        sum += b[i];
    }

    return sum;
}

int64_t SolveTask2(vector<int>& a, vector<int>& b, int moves, int n) {
    // i will try to get all gratest numbers in the b array
    // swapping two values from the same index will not affect the final sum
    // therefor it does not count as a move


    for (int i = 0; i < n; i++) {
        if (a[i] > b[i]) {
            int aux = a[i];
            a[i] = b[i];
            b[i] = aux;
        }
    }
    // sort the a array in descending order to get the highest numbers
    // that are not included in the sum yet
    // sort the b array in ascending order to get the lowest numbers
    // that are included in the sum, but shoud not be


    std::sort(a.begin(), a.end(), std::greater<int>());
    std::sort(b.begin(), b.end());

    long sum = 0;
    // start adding the numbers from the b array (the one with the highest
    // numbers), but if the number frum b is lower than a number from a,
    // it will take it into the sum as long as there are available moves

    for (int i = 0; i < n; i++) {
        if (a[i] > b[i] && moves > 0) {
            sum += a[i];
            moves--;
        } else {
            sum += b[i];
        }
    }
    return sum;
}

vector<int> ReadVector(istream& is, int size) {
    vector<int> vec(size);
    for (auto& num : vec) {
        is >> num;
    }
    return vec;
}

int main() {
    ifstream fin("nostory.in");
    ofstream fout("nostory.out");

    int task;
    fin >> task;

    int n, moves;
    if (task == 1) {
        fin >> n;
    } else {
        fin >> n >> moves;
    }

    auto a = ReadVector(fin, n);
    auto b = ReadVector(fin, n);

    auto res = task == 1 ? SolveTask1(a, b, n) : SolveTask2(a, b, moves, n);
    fout << res << "\n";

    return 0;
}

/*
 * Acest schelet citește datele de intrare și scrie răspunsul generat de voi,
 * astfel că e suficient să completați cele două metode.
 *
 * Scheletul este doar un punct de plecare, îl puteți modifica oricum doriți.
 *
 * Dacă păstrați scheletul, nu uitați să redenumiți clasa și fișierul.
 */

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintStream;
import java.io.Reader;
import java.text.CollationKey;
import java.util.Arrays;
import java.util.Collections;
import java.util.StringTokenizer;

public class Nostory {
	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("nostory.in"));

		var task = scanner.nextInt();
		var n = scanner.nextInt();
		var moves = task == 2 ? scanner.nextInt() : 0;

		var a = new int[n];
		for (var i = 0; i < n; i += 1) {
			a[i] = scanner.nextInt();
		}

		var b = new int[n];
		for (var i = 0; i < n; i += 1) {
			b[i] = scanner.nextInt();
		}

		try (var printer = new PrintStream("nostory.out")) {
			if (task == 1) {
				printer.println(solveTask1(a, b));
			} else {
				printer.println(solveTask2(a, b, moves));
			}
		}
	}

	private static long solveTask1(int[] a, int[] b) {
		long sum = 0;
		Integer[] boxedArr = Arrays.stream(a).boxed().toArray(Integer[]::new);
		Arrays.sort(boxedArr, Collections.reverseOrder());
		int[] descArr = Arrays.stream(boxedArr).mapToInt(Integer::intValue).toArray();

		Arrays.sort(b);
		for (int i = 0; i < descArr.length; i ++) {
			if (descArr[i] > b[i]) {
				sum += descArr[i];
			} else {
				sum += b[i];
			}
		}

		return sum;
	}

	private static long solveTask2(int[] a, int[] b, int moves) {
		int n = a.length;
		int[] take = new int[n];
		int[] rest = new int[n];
		long sum = 0;

		for (int i = 0; i < n; i ++) {
			if (a[i] > b[i]) {
				take[i] = a[i];
				rest[i] = b[i];
			} else {
				take[i] = b[i];
				rest[i] = a[i];
			}
		}

		Arrays.sort(take);
		Integer[] boxedArr = Arrays.stream(rest).boxed().toArray(Integer[]::new);
		Arrays.sort(boxedArr, Collections.reverseOrder());
		int[] descRest = Arrays.stream(boxedArr).mapToInt(Integer::intValue).toArray();

		int k = 0;

		while (k < moves) {
			if (descRest[k] > take[k]) {
				sum += descRest[k];
			} else {
				sum += take[k];
			}

			k++;
		}

		while (k < n) {
			sum += take[k];
			k++;
		}

		return sum;
	}

	/**
	 * A class for buffering read operations, inspired from here:
	 * https://pastebin.com/XGUjEyMN.
	 */
	private static class MyScanner {
		private BufferedReader br;
		private StringTokenizer st;

		public MyScanner(Reader reader) {
			br = new BufferedReader(reader);
		}

		public String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		public int nextInt() {
			return Integer.parseInt(next());
		}

		public long nextLong() {
			return Long.parseLong(next());
		}

		public double nextDouble() {
			return Double.parseDouble(next());
		}

		public String nextLine() {
			String str = "";
			try {
				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}
	}
}
